"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[725795],{766799:a=>{a.exports=JSON.parse('{"tag":{"label":"shadow","permalink":"/dst-api-webdocs/docs/tags/shadow","allTagsPath":"/dst-api-webdocs/docs/tags","count":21,"items":[{"id":"game-scripts/prefabs/armor_ruins","title":"Armor Ruins","description":"A wearable piece of high-defense armor that provides substantial damage absorption and integrates with DST\u2019s skinning and shadow level systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_ruins"},{"id":"game-scripts/prefabs/armor_voidcloth","title":"Armor Voidcloth","description":"A wearable item that grants shadow-aligned resistance, planar defense, and sets a negative sanity aura when equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_voidcloth"},{"id":"game-scripts/prefabs/bigshadowtentacle","title":"Bigshadowtentacle","description":"A boss-like shadow entity that engages in combat by attacking nearby targets, tracking them within range, and periodically reevaluating its target.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/bigshadowtentacle"},{"id":"game-scripts/prefabs/carrat_ghostracer","title":"Carrat Ghostracer","description":"A non-player character prefab representing a Ghost Racer carrat that participates in the Year of the Crow (YOTC) race, with stat-based performance modifiers and dynamic behavior during races.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carrat_ghostracer"},{"id":"game-scripts/prefabs/fused_shadeling","title":"Fused Shadeling","description":"Prefab for a hostile boss-like shadow entity that spawns from portals, maintains aggression range, and interacts with sanity, combat, and planar damage systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fused_shadeling"},{"id":"game-scripts/prefabs/glasscutter","title":"Glasscutter","description":"A consumable weapon prefab that deals damage with finite uses, deals bonus damage against shadow enemies, and provides visual feedback via equipped animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glasscutter"},{"id":"game-scripts/prefabs/magician_chest","title":"Magician Chest","description":"Serves as a shadow dimension storage container for the Magician character, enabling item storage with burnable and hauntable properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/magician_chest"},{"id":"game-scripts/prefabs/nightmarecreature","title":"Nightmarecreature","description":"Factory function for creating nightmare creature prefabs with dynamic behavior based on game world state, such as shadow rift presence and nightmare dawn.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightmarecreature"},{"id":"game-scripts/prefabs/nightsword","title":"Nightsword","description":"A consumable weapon that deals shadow damage and loses one use each time it is swung.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightsword"},{"id":"game-scripts/brains/oceanshadowcreaturebrain","title":"Oceanshadowcreaturebrain","description":"Controls the AI behavior of ocean-based shadow creatures, including target management, harassment actions, and conditional teleportation to land.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/oceanshadowcreaturebrain"},{"id":"game-scripts/prefabs/player_hosted","title":"Player Hosted","description":"Creates a non-player hostile entity that mimics a player model and behaves as a parasitic shadow thrall with combat, sanity-draining, and retention behavior toward its designated owner.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/player_hosted"},{"id":"game-scripts/prefabs/ruins_bat","title":"Ruins Bat","description":"A consumable equippable weapon that allows the player to summon shadow tentacles on attack, with a limited number of uses and shadow level scaling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_bat"},{"id":"game-scripts/prefabs/ruins_shadeling","title":"Ruins Shadeling","description":"A non-hostile ambient shadow creature that respawns in the Ruins and spawns different loot based on shadow rift presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ruins_shadeling"},{"id":"game-scripts/prefabs/shadow_leech","title":"Shadow Leech","description":"A hostile shadow creature prefab that spawns in response to the Daywalker, tracks it via EntityTracker, and applies a sanity aura based on observer perception.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadow_leech"},{"id":"game-scripts/brains/shadowcreaturebrain","title":"Shadowcreaturebrain","description":"Implements the AI behavior for shadow creatures, including target tracking, harassment mechanics, and conditional chasing or loitering based on combat state and locomotion speed.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadowcreaturebrain"},{"id":"game-scripts/components/shadowlevel","title":"Shadowlevel","description":"Manages the shadow level state of an entity by storing a base level and an optional dynamic level function.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowlevel"},{"id":"game-scripts/components/shadowsubmissive","title":"Shadowsubmissive","description":"Grants an entity the `shadowsubmissive` tag and manages its behavioral response to shadow-dominant entities by tracking attacks and restoring the `shadowdominance` tag after a delay if conditions are met.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowsubmissive"},{"id":"game-scripts/prefabs/shadowthrall_horns","title":"Shadowthrall Horns","description":"A boss enemy prefab with shadow-aligned alignment, using custom combat logic, brain, and team-based state synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowthrall_horns"},{"id":"game-scripts/prefabs/stageusher","title":"Stageusher","description":"Manages the stageusher entity, a large shadowy boss that alternates between standing (attacking) and sitting (repairing) states, using shadow hands and arms to pursue and damage players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stageusher"},{"id":"game-scripts/prefabs/thurible","title":"Thurible","description":"Manages the behavior and state of the Thurible item, a lantern that lights up in the Dark and attracts Shadow Creatures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thurible"},{"id":"game-scripts/prefabs/voidcloth_scythe","title":"Voidcloth Scythe","description":"A multiplayer-ready weapon that synergizes with the Voidcloth Set, providing increased damage and planar damage when equipped alongside a Voidcloth Hat, while also enabling shadow-empowered area attacks and harvest automation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/voidcloth_scythe"}],"unlisted":false}}')}}]);